{
  "grammar": [
    {
      "pattern": "Subject + 來 + Taiwan + 多久 + 了？",
      "structure": ["Subject", "來", "Location", "多久", "了"],
      "explanation_en": "Use this pattern to ask how long someone has been in a place. It emphasizes the duration from arrival to now.",
      "title": "Asking Duration in Taiwan",
      "meaning": "How long have you been in Taiwan?",
      "when_to_use": ["When meeting someone new and wanting to know their stay duration", "In casual conversation to learn about someone's background"],
      "when_not_to_use": ["When asking about future plans", "When the person has never been to Taiwan"],
      "pragmatic_notes": "In Taiwan, this is a common icebreaker question. It shows interest in the person's experience here.",
      "word_order_notes": "Place '來' before the location and '多久' after it. '了' at the end indicates a change or ongoing state.",
      "english_contrast": "English uses 'How long have you been in...?' with present perfect. Chinese uses '來 + location + 多久 + 了'.",
      "korean_contrast": "Korean uses '얼마나 오래 ...에 있었어요?' with past tense. Chinese uses present structure with '了'.",
      "negative_examples": [
        {
          "text": "你來台灣多久？",
          "error": "Missing '了' at the end. '了' is needed to show the action started in the past and continues."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你多久來台灣？",
          "error": "Word order is wrong. '多久' should come after the location, not before '來'."
        }
      ],
      "transformation_drills": ["Change '你' to '他' and adjust the sentence.", "Change '台灣' to '台北'."],
      "production_drills": ["Ask a classmate how long they have been in Taiwan.", "Answer the question about yourself."],
      "common_error_patterns": ["Forgetting '了' at the end", "Placing '多久' before '來'"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 來 + Location + 多久 + 了.",
        "politeness": "This is neutral. Add '請問' for more politeness.",
        "vocabulary": "Use '台灣' or specific city names like '台北'."
      }
    },
    {
      "pattern": "Subject + 為了 + reason + 來 + location",
      "structure": ["Subject", "為了", "reason", "來", "location"],
      "explanation_en": "Use this pattern to explain the purpose or reason for coming to a place. '為了' means 'in order to'.",
      "title": "Explaining Purpose with 為了",
      "meaning": "I came to Taiwan in order to...",
      "when_to_use": ["When explaining why you came to Taiwan", "When stating your goal or motivation"],
      "when_not_to_use": ["When describing an action without a clear purpose", "When the reason is a simple preference like '喜歡'"],
      "pragmatic_notes": "In Taiwan, people often ask '你為什麼來台灣？' Use '為了' to give a clear, goal-oriented answer.",
      "word_order_notes": "Place '為了' before the reason, then '來' before the location. The reason can be a verb phrase or noun.",
      "english_contrast": "English uses 'in order to' or 'for'. Chinese uses '為了' directly before the reason.",
      "korean_contrast": "Korean uses '위해서' after the reason. Chinese places '為了' before the reason.",
      "negative_examples": [
        {
          "text": "我來台灣為了學中文。",
          "error": "Word order is incorrect. '為了' should come before '來', not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我為了學中文來台灣。",
          "error": "This is actually correct! But ensure the reason is a verb phrase or noun, not a full sentence."
        }
      ],
      "transformation_drills": ["Change '學中文' to '工作' and adjust.", "Change '台灣' to '台北'."],
      "production_drills": ["Tell a partner why you came to Taiwan using '為了'.", "Ask a classmate why they came."],
      "common_error_patterns": ["Placing '為了' after '來'", "Using a full sentence as the reason"],
      "repair_feedback": {
        "word_order": "Correct order: Subject + 為了 + reason + 來 + location.",
        "politeness": "This is neutral. Add '我是' for emphasis: '我是為了...'",
        "vocabulary": "Use verbs like '學', '工作', '旅行' as reasons."
      }
    },
    {
      "pattern": "Subject + 學 + 中文 + 的 + 目標 + 是 + goal",
      "structure": ["Subject", "學", "中文", "的", "目標", "是", "goal"],
      "explanation_en": "Use this pattern to state your goal for learning Chinese. '的' connects '學中文' to '目標'.",
      "title": "Stating Learning Goals",
      "meaning": "My goal in learning Chinese is...",
      "when_to_use": ["When explaining your motivation for learning Chinese", "In a class or interview setting"],
      "when_not_to_use": ["When talking about daily activities unrelated to learning", "When the goal is very short-term like '今天'"],
      "pragmatic_notes": "In Taiwan, people appreciate clear goals. This pattern shows you are serious about learning.",
      "word_order_notes": "Place '學中文的目標' as a noun phrase before '是'. The goal can be a verb phrase or noun.",
      "english_contrast": "English uses 'My goal in learning Chinese is...'. Chinese uses '學中文的目標是...'.",
      "korean_contrast": "Korean uses '중국어를 배우는 목표는...입니다'. Chinese is more direct with '的'.",
      "negative_examples": [
        {
          "text": "我的目標學中文是流利。",
          "error": "Word order is wrong. '學中文的目標' should be together before '是'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我學中文的目標是流利。",
          "error": "Missing '說' or '講'. The goal should be a verb phrase like '說流利的中文'."
        }
      ],
      "transformation_drills": ["Change '流利' to '通過考試' and adjust.", "Change '學中文' to '學英文'."],
      "production_drills": ["Tell a partner your goal for learning Chinese.", "Ask a classmate their goal."],
      "common_error_patterns": ["Separating '學中文的目標'", "Using an adjective alone as the goal"],
      "repair_feedback": {
        "word_order": "Correct order: Subject + 學中文的目標 + 是 + goal.",
        "politeness": "This is neutral. Add '我的' for clarity.",
        "vocabulary": "Use goals like '說流利的中文', '通過考試', '工作'."
      }
    }
  ]
}
